import React, { createContext, useState, useEffect, useContext } from 'react';

// Language translations
const translations = {
  en: {
    // Navigation
    'nav.home': 'Home',
    'nav.upload': 'Upload Video',
    'nav.myVideos': 'My Videos',
    'nav.admin': 'Admin Panel',
    'nav.login': 'Login',
    'nav.register': 'Register',
