    'login.noAccount': "Don't have an account?",
    'login.signUp': 'Sign up now',

    // Register page
    'register.title': 'Create Account',
    'register.subtitle': 'Join our community today',
    'register.username': 'Username',
    'register.email': 'Email',
    'register.password': 'Password',
    'register.confirmPassword': 'Confirm Password',
    'register.button': 'Sign Up',
    'register.hasAccount': 'Already have an account?',
    'register.signIn': 'Sign in now',

    // Theme
    'theme.toggle': 'Toggle dark mode',

    // Language
    'language.switch': 'Switch Language',
    'language.english': 'English',
    'language.chinese': '中文',

    // Footer
    'footer.about': 'About Us',
    'footer.aboutDesc': 'Lightweight video sharing platform providing quality video viewing and sharing experience.',
    'footer.quickLinks': 'Quick Links',
    'footer.contact': 'Contact Us',
    'footer.contactDesc': 'If you have any questions or suggestions, feel free to contact us.',
    'footer.copyright': 'All rights reserved.'
  },
  zh: {
    // Navigation
    'nav.home': '首页',
    'nav.upload': '上传视频',
    'nav.myVideos': '我的视频',
    'nav.admin': '管理后台',
    'nav.login': '登录',
    'nav.register': '注册',
    'nav.logout': '退出',

    // Home page
    'home.title': '发现精彩视频',
    'home.subtitle': '探索、分享、观看无限精彩内容',
    'home.searchPlaceholder': '搜索视频标题、作者、简介...',
    'home.recommended': '推荐视频',
    'home.viewAll': '查看全部 →',
    'home.noVideos': '暂无视频',
